public class Main {
    static boolean isValidUsername(String s) {
        if (s == null || s.trim().isEmpty()) return false;
        if (s.length() < 3 || s.length() > 20) return false;
        return s.matches("[a-zA-Z0-9_]+");
    }

    static boolean isValidEmail(String s) {
        if (s == null || s.trim().isEmpty()) return false;
        if (!s.contains("@") || !s.contains(".")) return false;
        String[] parts = s.split("@");
        if (parts.length != 2) return false;
        return parts[0].length() > 0 && parts[1].length() > 3;
    }

    static boolean isStrongPassword(String s) {
        if (s == null || s.length() < 8) return false;
        boolean hasUpper = false, hasLower = false, hasDigit = false, hasSpecial = false;
        for (char c : s.toCharArray()) {
            if (Character.isUpperCase(c)) hasUpper = true;
            if (Character.isLowerCase(c)) hasLower = true;
            if (Character.isDigit(c)) hasDigit = true;
            if (!Character.isLetterOrDigit(c)) hasSpecial = true;
        }
        return hasUpper && hasLower && hasDigit && hasSpecial;
    }

    public static void main(String[] args) {
        System.out.println("Username 'alice_99': " + isValidUsername("alice_99"));
        System.out.println("Username 'ab': " + isValidUsername("ab"));
        System.out.println("Username '<script>': " + isValidUsername("<script>"));
        System.out.println("Email 'a@b.com': " + isValidEmail("a@b.com"));
        System.out.println("Email 'invalid': " + isValidEmail("invalid"));
        System.out.println("Password 'Str0ng!x': " + isStrongPassword("Str0ng!x"));
        System.out.println("Password 'weak': " + isStrongPassword("weak"));
    }
}

